const agentOutput = $('AI Agent').first().json;
let text = (agentOutput && agentOutput.output) ? String(agentOutput.output) : '';

if (text) {
  // Convert markdown headers to bold
  text = text.replace(/^#{1,6}\s+(.+)$/gm, '**$1**');

  // Remove horizontal rules
  text = text.replace(/^[\s]*([-*_]){3,}[\s]*$/gm, '');

  // Strip emojis
  text = text.replace(/[\u{1F600}-\u{1F64F}\u{1F300}-\u{1F5FF}\u{1F680}-\u{1F6FF}\u{1F1E0}-\u{1F1FF}\u{2600}-\u{26FF}\u{2700}-\u{27BF}\u{FE00}-\u{FE0F}\u{1F900}-\u{1F9FF}\u{1FA00}-\u{1FA6F}\u{1FA70}-\u{1FAFF}\u{200D}\u{20E3}\u{E0020}-\u{E007F}\u{2194}-\u{2199}\u{2122}\u{2139}\u{2300}-\u{23FF}\u{2B05}-\u{2B55}\u{25A0}-\u{25FF}\u{2934}-\u{2935}]/gu, '');

  // Convert markdown tables to plain text
  const lines = text.split('\n');
  const result = [];
  let inTable = false;
  let headers = [];
  for (let i = 0; i < lines.length; i++) {
    const line = lines[i].trim();
    if (/^\|.*\|$/.test(line)) {
      if (/^\|[\s\-:|]+\|$/.test(line)) continue;
      const cells = line.split('|').filter(c => c.trim() !== '').map(c => c.trim());
      if (!inTable) { inTable = true; headers = cells; continue; }
      result.push(cells.map((cell, idx) => headers[idx] ? `${headers[idx]}: ${cell}` : cell).join(' | '));
    } else {
      if (inTable) { inTable = false; headers = []; }
      result.push(lines[i]);
    }
  }
  text = result.join('\n');

  // Collapse excessive blank lines
  text = text.replace(/\n{3,}/g, '\n\n');
  text = text.trim();
}

return [{ json: { output: text } }];

function sq(v) {
  return v == null ? 'NULL' : "'" + String(v).replace(/'/g, "''") + "'";
}

const chatTrigger = $('Chat Trigger').first().json;
const agentOutput = $('AI Agent').first().json;

const sessionId = chatTrigger.sessionId || null;
const userInput = $('Code: Inject Deal ID').first().json.original_input || chatTrigger.chatInput || null;
const output = agentOutput.output || null;
const messageId = (sessionId || '') + '_' + Date.now();
const executionId = $execution.id;

const sql = `INSERT INTO agent_traces (session_id, message_id, user_input, agent_output, status) VALUES (${sq(sessionId)}, ${sq(messageId)}, ${sq(userInput)}, ${sq(output)}, 'success') RETURNING id;`;

return [{ json: { insert_sql: sql, execution_id: executionId } }];

const chatTrigger = $('Chat Trigger').first().json;
const sessionId = chatTrigger.sessionId || '';
const rawInput = chatTrigger.chatInput || '';

let deal_id = 'unknown';
let isPipeline = false;

if (sessionId.startsWith('pipeline_')) {
  deal_id = '__pipeline__';
  isPipeline = true;
} else if (sessionId.startsWith('deal_')) {
  deal_id = sessionId.replace(/^deal_/, '').replace(/_\d+$/, '');
}

const scopeTag = isPipeline
  ? '[SCOPE: PIPELINE — ALL DEALS]'
  : `[DEAL_SCOPE: ${deal_id}]`;

const enrichedInput = `${scopeTag} ${rawInput}`;

return [{
  json: {
    chatInput: enrichedInput,
    sessionId: sessionId,
    deal_id: deal_id,
    is_pipeline: isPipeline,
    original_input: rawInput
  }
}];

